CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;


DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260624120241_Intial_Script') THEN
    CREATE TABLE "Meetings" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Name" character varying(50) NOT NULL,
        "Description" character varying(100),
        "TemplateId" character varying(50) NOT NULL,
        "AudioFileName" character varying(255) NOT NULL,
        "AudioFileSize" bigint NOT NULL,
        "AudioStoragePath" text,
        "Status" character varying(20) NOT NULL,
        "ErrorMessage" character varying(500),
        "Transcript" text,
        "ExtractionResultJson" text NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        "CompletedAt" timestamp with time zone,
        CONSTRAINT "PK_Meetings" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260624120241_Intial_Script') THEN
    CREATE INDEX "IX_Meetings_CreatedAt" ON "Meetings" ("CreatedAt");
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260624120241_Intial_Script') THEN
    CREATE INDEX "IX_Meetings_Status" ON "Meetings" ("Status");
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260624120241_Intial_Script') THEN
    INSERT INTO "__EFMigrationsHistory" ("MigrationId", "ProductVersion")
    VALUES ('20260624120241_Intial_Script', '8.0.0');
    END IF;
END $EF$;
COMMIT;

